function maxArea(height) {
    const nums = Array.isArray(height) ? height.filter((x) => !Number.isNaN(x)) : [];
    if (nums.length < 2) return 0;
    let left = 0;
    let right = nums.length - 1;
    let best = 0;
    while (left < right) {
        const area = Math.min(nums[left], nums[right]) * (right - left);
        if (area > best) best = area;
        if (nums[left] < nums[right]) left += 1;
        else right -= 1;
    }
    return best;
}

